import{_ as e,o as n,c as s,O as t}from"./chunks/framework.92cbe775.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/product/scenarios.md","filePath":"en/product/scenarios.md","lastUpdated":1776068451000}'),i={name:"en/product/scenarios.md"};function r(l,a,c,o,d,p){return n(),s("div",null,a[0]||(a[0]=[t('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Scenarios</p><h1>Scenarios</h1><div class="brand-hero__panel"><span class="brand-pill">Usage Thesis</span><strong>The point is not to make AI talk more. The point is to make real tasks land.</strong><p>Every scenario is still organized around the same mainline: entry, confirmation, execution, audit trail, and governance.</p></div><p class="brand-lead"> ExecGov is not an abstract concept site. It exists to solve <strong>how real tasks can be scheduled and executed safely by AI</strong>. The more real the scenario is, the clearer the platform&#39;s value and boundaries become. </p><div class="brand-chip-list"><span class="brand-chip">Operations-data automation</span><span class="brand-chip">Script governance &amp; ops</span><span class="brand-chip">Private-delivery customers</span><span class="brand-chip">Hybrid execution</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../contact.html#lead-form">Discuss a real scenario</a><a class="cta-button" href="./capabilities.html">View capabilities</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // SCENARIO MAP</span><span>DOC 02</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">scenarioA</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;ops_automation_team&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">scenarioB</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;customer_delivery_project&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">scenarioC</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;free_entry&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;local_bridge&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;template_ops&#39;</span><span class="matrix-panel__punct">]</span></span></div><div class="matrix-panel__callout">SCENARIOS SHOULD MATCH REAL BUYING INTENT</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">delivery</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">ops</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">local_bridge</span></span></div></div></div></section><section class="brand-card"><p class="brand-kicker">Priority Segments</p><h2>The three customer groups most worth prioritizing right now</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>E-commerce, content, and operations-data automation</h3><p>These teams already have scraping, cleanup, reporting, import-export, or data-processing scripts, but their entry points are scattered, execution is messy, and result tracing is painful.</p></article><article class="brand-card brand-card--nested"><h3>Technical teams doing script governance and automation ops</h3><p>These scenarios include log cleanup, inspection, batch jobs, scheduled reporting, script permission control, and execution auditing.</p></article><article class="brand-card brand-card--nested"><h3>Smaller formal customers that need intranet access or private deployment</h3><p>These customers want clear tenant isolation, permission boundaries, intranet execution, and formal delivery, but do not want to start with a heavy system.</p></article></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">01</p><h2>Internal team workflow automation</h2><ul class="brand-list"><li>The team already has Python or automation scripts, but usage is scattered</li><li>They want one unified entry instead of having every person run environments manually</li><li>Execution needs confirmation, audit trail, and controlled visibility</li><li>This fits e-commerce, content, and operations-data tasks such as cleanup, batch processing, and periodic reporting</li></ul></article><article class="brand-card"><p class="brand-kicker">02</p><h2>Formal customer-isolated delivery</h2><ul class="brand-list"><li>One isolated environment per customer</li><li>The platform side centrally manages customers, templates, logs, and announcements</li><li>The same foundation keeps getting reused for multiple customers</li><li>The focus is a clear tenant boundary plus governability, not mixing all customers inside one backend</li></ul></article><article class="brand-card"><p class="brand-kicker">03</p><h2>Entry path for individuals and smaller teams</h2><ul class="brand-list"><li>Organize local scripts into describable and callable capabilities</li><li>Expose and run personal tools through one unified entry</li><li>Use the CLI to connect local scripts into the platform</li><li>This is both an experience entry and an upgrade entry for deeper collaboration later</li></ul></article></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">04</p><h2>Hybrid execution and local onboarding</h2><ul class="brand-list"><li>The task depends on local file directories</li><li>The task depends on intranet resources, private data sources, or a local network boundary</li><li>The web side handles entry, planning, confirmation, and audit trail</li><li>The local environment plus CLI / Agent handles actual execution</li></ul></article><article class="brand-card"><p class="brand-kicker">05</p><h2>Super-admin governance and template distribution</h2><ul class="brand-list"><li>Template distribution</li><li>Announcement delivery</li><li>Customer and tenant governance</li><li>Platform audit, rollback, and operational ledgers</li></ul></article><article class="brand-card"><p class="brand-kicker">06</p><h2>Script governance and automation ops</h2><ul class="brand-list"><li>Fits log cleanup, inspection, batch processing, and scheduled tasks</li><li>Emphasizes a unified script entry, manual confirmation, and execution audit trail</li><li>Fits controlled scheduling against local environments, local scripts, or intranet resources</li><li>Matches the platform&#39;s current script-first maturity boundary</li></ul></article></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Boss View 01</p><h2>What work does it actually save a team from</h2><p>It turns repetitive scripts, data-processing tasks, and internal flows into one unified entry. The team no longer has to remember a pile of commands, hunt for scripts, and ask multiple people how to run them.</p></article><article class="brand-card"><p class="brand-kicker">Boss View 02</p><h2>Why does it not spin out of control</h2><p>The system is built around permission boundaries, manual confirmation, and execution audit trails. The point is not to let AI improvise freely. The point is to make automation genuinely governable.</p></article><article class="brand-card"><p class="brand-kicker">Boss View 03</p><h2>Why is it worth continuing to invest in</h2><p>The value is not just one automation task. The value is turning scattered scripts into a reusable, continuously updateable, long-lived capability foundation.</p></article></section><section class="brand-card"><p class="brand-kicker">Future Scenarios</p><h2>Capability scenarios the platform can expand into over time</h2><p>Python-script scenarios are the most mature today, but the same foundation is suited for the directions below as the platform evolves. This is about room to grow, not a claim that everything is already a standardized product.</p><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>Enterprise interface automation</h3><p>Bring SMS, email, ERP, CRM, OA, webhooks, and internal service interfaces into one unified entry and audit chain.</p></article><article class="brand-card brand-card--nested"><h3>Data read-write and synchronization</h3><p>Bring database reads and writes, report synchronization, warehouse write-back, and master-data updates into standardized capability units.</p></article><article class="brand-card brand-card--nested"><h3>Standard document generation</h3><p>Turn contracts, quotations, weekly reports, project plans, and standard industry documents into template-driven execution flows.</p></article><article class="brand-card brand-card--nested"><h3>Approval and ticket flow</h3><p>Bring approval initiation, ticket progression, workflow-node triggers, and state queries into governed actions.</p></article><article class="brand-card brand-card--nested"><h3>Specialized AI services</h3><p>Bring document parsing, OCR, speech recognition, image generation, and similar model services into one governance chain.</p></article><article class="brand-card brand-card--nested"><h3>Ops and alert linkage</h3><p>Continue standardizing inspection, backup, log cleanup, alert notification, and service health checks.</p></article></div></section><section class="brand-card"><p class="brand-kicker">How To Judge Fit</p><h2>How to judge whether the fit is high</h2><div class="brand-link-grid"><a class="brand-link-card" href="./capabilities.html"><span>Capability Fit</span><strong>You already have scripts, but no unified governance</strong><p>The capabilities page shows whether multi-tenancy, execution closure, and template governance fit the real need.</p></a><a class="brand-link-card" href="./deployment.html"><span>Deployment Fit</span><strong>You are worried about local environments, intranet boundaries, or hybrid execution</strong><p>The deployment page shows how the control plane and the execution side can be separated under one governance model.</p></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead Fit</span><strong>You want to discuss a real scenario directly</strong><p>Submit a lead and decide early whether this should stay on the standard team path or move directly into enterprise delivery.</p></a><a class="brand-link-card" href="./cli.html"><span>CLI Fit</span><strong>You already have local scripts and want a lower-cost way to connect them first</strong><p>The CLI Guide helps you verify whether the current login, registration, execution, and Agent skeleton match the way you want to land the work.</p></a></div></section><section class="brand-card"><p class="brand-kicker">Scenario To Delivery</p><h2>Key materials after the scenario is confirmed</h2><div class="brand-link-grid brand-link-grid--three"><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>The scenario depends on file input and result artifacts</strong><p>If the task works with Excel, CSV, archives, or other input files and needs result files back, the file-path explanation becomes the most direct next page.</p></a><a class="brand-link-card" href="./deliverables.html"><span>Deliverables</span><strong>How the scenario finally turns into a delivery package</strong><p>Once a scenario is proven, the next question is what entry points, instructions, and result artifacts the customer will actually receive.</p></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>What should be prepared before scenario onboarding</strong><p>If the real script capability and example files already exist, align the script directory, README, dependencies, and risk boundary before delivery discussions get deeper.</p></a></div></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>After the scenario fits, read delivery and onboarding materials together</h2><p class="brand-lead">This page is for testing whether a project shape is real. Once it is, files, deliverables, and onboarding preparation become more important than more broad scenario talk.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./customer-flow.html"><span>Flow</span><strong>Customer Flow / Delivery</strong></a><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>Files &amp; Results</strong></a><a class="brand-link-card" href="./deliverables.html"><span>Deliverables</span><strong>Deliverables</strong></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>Onboarding Checklist</strong></a></div></div></section></div>',1)]))}const m=e(i,[["render",r]]);export{u as __pageData,m as default};
